import React, { useState, useRef, useEffect } from 'react';

function DrawingCanvas({ cameraData, onSave, onBack }) {
  const [drawing, setDrawing] = useState(false);
  const [lines, setLines] = useState([]);
  const [ix, setIx] = useState(-1);
  const [iy, setIy] = useState(-1);
  const [showPreview, setShowPreview] = useState(false);
  const canvasRef = useRef(null);
  const imageRef = useRef(null);

  const handleMouseDown = (e) => {
    if (!canvasRef.current || !imageRef.current || lines.length >= 2) return;

    const canvas = canvasRef.current;
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;

    const x = (e.clientX - rect.left) * scaleX;
    const y = (e.clientY - rect.top) * scaleY;

    setDrawing(true);
    setIx(x);
    setIy(y);
  };

  const handleMouseMove = (e) => {
    if (!drawing || !canvasRef.current || lines.length >= 2) return;

    const canvas = canvasRef.current;
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;

    const x = (e.clientX - rect.left) * scaleX;
    const y = (e.clientY - rect.top) * scaleY;

    const ctx = canvas.getContext('2d');
    redrawAll();

    ctx.beginPath();
    ctx.moveTo(ix, iy);
    ctx.lineTo(x, y);

    if (lines.length === 0) {
      ctx.strokeStyle = '#000000';
      ctx.lineWidth = 2;
      ctx.stroke();
    } else if (lines.length === 1) {
      drawArrow(ctx, ix, iy, x, y, '#ff0000', 2);
    }
  };

  const handleMouseUp = (e) => {
    if (!drawing || !canvasRef.current || lines.length >= 2) return;

    const canvas = canvasRef.current;
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;

    const x = (e.clientX - rect.left) * scaleX;
    const y = (e.clientY - rect.top) * scaleY;

    const normStartX = ix / canvas.width;
    const normStartY = iy / canvas.height;
    const normEndX = x / canvas.width;
    const normEndY = y / canvas.height;

    const newLine = {
      start: { x: normStartX, y: normStartY },
      end: { x: normEndX, y: normEndY }
    };

    setLines([...lines, newLine]);
    setDrawing(false);

    const ctx = canvas.getContext('2d');

    if (lines.length === 0) {
      ctx.beginPath();
      ctx.moveTo(ix, iy);
      ctx.lineTo(x, y);
      ctx.strokeStyle = '#000000';
      ctx.lineWidth = 3;
      ctx.stroke();
    } else if (lines.length === 1) {
      drawArrow(ctx, ix, iy, x, y, '#ff0000', 4);
      // Tự động hiển thị preview sau khi vẽ xong
      setShowPreview(true);
    }
  };

  const drawArrow = (ctx, fromX, fromY, toX, toY, color, width) => {
    const headLength = 20;
    const angle = Math.atan2(toY - fromY, toX - fromX);

    ctx.beginPath();
    ctx.moveTo(fromX, fromY);
    ctx.lineTo(toX, toY);
    ctx.strokeStyle = color;
    ctx.lineWidth = width;
    ctx.stroke();

    ctx.beginPath();
    ctx.moveTo(toX, toY);
    ctx.lineTo(
      toX - headLength * Math.cos(angle - Math.PI / 6),
      toY - headLength * Math.sin(angle - Math.PI / 6)
    );
    ctx.lineTo(
      toX - headLength * Math.cos(angle + Math.PI / 6),
      toY - headLength * Math.sin(angle + Math.PI / 6)
    );
    ctx.closePath();
    ctx.fillStyle = color;
    ctx.fill();
  };

  const redrawAll = () => {
    if (!canvasRef.current || !imageRef.current) return;

    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    lines.forEach((line, index) => {
      const startX = line.start.x * canvas.width;
      const startY = line.start.y * canvas.height;
      const endX = line.end.x * canvas.width;
      const endY = line.end.y * canvas.height;

      if (index === 0) {
        ctx.beginPath();
        ctx.moveTo(startX, startY);
        ctx.lineTo(endX, endY);
        ctx.strokeStyle = '#000000';
        ctx.lineWidth = 3;
        ctx.stroke();
      } else if (index === 1) {
        drawArrow(ctx, startX, startY, endX, endY, '#ff0000', 4);
      }
    });
  };

  const generatePreviewJSON = () => {
    if (lines.length < 2) return null;

    const axis = [lines[0].start.x, lines[0].start.y, lines[0].end.x, lines[0].end.y];
    const coord = [lines[1].start.x, lines[1].start.y, lines[1].end.x, lines[1].end.y];

    return {
      list_camera: [
        {
          cam_info: {
            url: cameraData.rtspUrl,
            cam_id: generateUUID()
          },
          config: {
            direction: [],
            heatmap: {},
            layout: {},
            zone: [{
              ID: generateUUID(),
              type: 1,
              axis: axis.map(v => Number(v.toFixed(3))),
              coord: coord.map(v => Number(v.toFixed(3))),
            }],
            reid: {
              faiss_switch: 0.6,
              faiss_staff_db: 0.8
            }
          }
        }
      ]
    };
  };

  const generateUUID = () => {
    return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
      const r = Math.random() * 16 | 0;
      const v = c === 'x' ? r : (r & 0x3 | 0x8);
      return v.toString(16);
    });
  };

  const handleSave = () => {
    if (lines.length < 2) {
      alert('Cần vẽ đủ Axis và Coord');
      return;
    }

    const axis = [lines[0].start.x, lines[0].start.y, lines[0].end.x, lines[0].end.y];
    const coord = [lines[1].start.x, lines[1].start.y, lines[1].end.x, lines[1].end.y];

    const config = {
      zone: [{
        ID: generateUUID(),
        type: 1,
        axis: axis,
        coord: coord
      }],
      reid: {
        faiss_switch: 0.6,
        faiss_staff_db: 0.8
      }
    };

    onSave(config);
  };

  const handleCopyJSON = () => {
    const preview = generatePreviewJSON();
    if (preview) {
      navigator.clipboard.writeText(JSON.stringify(preview, null, 2));
      alert('Đã copy JSON vào clipboard!');
    }
  };

  useEffect(() => {
    redrawAll();
  }, [lines]);

  const previewJSON = generatePreviewJSON();

  return (
    <div className="drawing-canvas">
      <div className="instructions">
        <h4>Hướng dẫn vẽ:</h4>
        <p>1. Kéo thả chuột vẽ Axis (line đen)</p>
        <p>2. Kéo thả chuột vẽ Coord (mũi tên đỏ)</p>
      </div>

      <div className="canvas-container">
        <img 
          ref={imageRef}
          src={cameraData.imagePreview} 
          alt="Camera"
          onLoad={() => {
            if (canvasRef.current && imageRef.current) {
              canvasRef.current.width = imageRef.current.width;
              canvasRef.current.height = imageRef.current.height;
              redrawAll();
            }
          }}
        />
        <canvas
          ref={canvasRef}
          onMouseDown={handleMouseDown}
          onMouseMove={handleMouseMove}
          onMouseUp={handleMouseUp}
          onMouseLeave={() => setDrawing(false)}
        />
      </div>

      <div className="status">
        <div className="status-item">
          <span className="status-label">Axis:</span>
          <span className={`status-value ${lines.length >= 1 ? 'completed' : 'pending'}`}>
            {lines.length >= 1 ? '✓ Đã vẽ' : '⏳ Chưa vẽ'}
          </span>
        </div>
        <div className="status-item">
          <span className="status-label">Coord:</span>
          <span className={`status-value ${lines.length >= 2 ? 'completed' : 'pending'}`}>
            {lines.length >= 2 ? '✓ Đã vẽ' : '⏳ Chưa vẽ'}
          </span>
        </div>
      </div>

      {/* Preview JSON */}
      {showPreview && previewJSON && (
        <div className="preview-section">
          <div className="preview-header">
            <h4>📦 Kết quả JSON:</h4>
            <button onClick={handleCopyJSON} className="btn-copy">
              📋 Copy
            </button>
          </div>
          <pre className="json-preview">
            {JSON.stringify(previewJSON, null, 2)}
          </pre>

          <div className="preview-details">
            <h5>Chi tiết tọa độ:</h5>
            <div className="coord-details">
              <div className="coord-row">
                <span className="coord-label">Axis:</span>
                <span className="coord-value">
                  [{previewJSON.list_camera[0].config.zone[0].axis.map(v => v.toFixed(3)).join(', ')}]
                </span>
              </div>
              <div className="coord-row">
                <span className="coord-label">Coord:</span>
                <span className="coord-value">
                  [{previewJSON.list_camera[0].config.zone[0].coord.map(v => v.toFixed(3)).join(', ')}]
                </span>
              </div>
            </div>
          </div>
        </div>
      )}

      <div className="actions">
        <button onClick={onBack} className="btn-back">← Quay lại</button>
        <button 
          onClick={handleSave} 
          className="btn-save"
          disabled={lines.length < 2}
        >
          {lines.length < 2 ? 'Vẽ đủ 2 đường' : '💾 Lưu camera'}
        </button>
      </div>

      <style jsx>{`
